const crypto = require('crypto');
const https  = require('https');

const APP_KEY    = 'db98a65eba39bf6886faf56e9249589e';
const APP_SECRET = '3896fff8060522f365d380dc03db8a6d57c5fad6';

const creds = $input.first().json;
const ACCESS_TOKEN = creds.access_token;
if (!ACCESS_TOKEN) throw new Error('No access_token in config.temu_credentials');

// Construim un lookup category_id → category_name pentru numele prietenos
let catalogCats = creds.categories;
if (typeof catalogCats === 'string') {
  try { catalogCats = JSON.parse(catalogCats); } catch(e) { catalogCats = []; }
}
const catNameById = {};
for (const c of (catalogCats || [])) {
  catNameById[String(c.category_id)] = c.category_name;
}

// Body-ul webhook-ului: {products: [{asin, title, description?, imageUrl}]}
const body = $('Webhook Temu Recommend Bulk').first().json.body || {};
const products = Array.isArray(body.products) ? body.products : [];

if (!products.length) {
  return [{ json: { success: false, error: 'no_products', recommendations: [] } }];
}

function buildSign(params) {
  const keys = Object.keys(params).sort();
  let s = APP_SECRET;
  for (const k of keys) s += k + String(params[k]);
  s += APP_SECRET;
  return crypto.createHash('md5').update(s).digest('hex').toUpperCase();
}

async function temuPost(type, reqBody = {}) {
  const timestamp = String(Math.floor(Date.now() / 1000));
  const sysParams = { type, app_key: APP_KEY, access_token: ACCESS_TOKEN, timestamp, data_type: 'JSON' };
  const sign = buildSign(sysParams);
  const qs = Object.entries({ ...sysParams, sign }).map(([k,v]) => `${k}=${encodeURIComponent(v)}`).join('&');
  const payload = JSON.stringify(Object.keys(reqBody).length ? { request: reqBody } : {});

  return new Promise((resolve, reject) => {
    const opts = {
      hostname: 'openapi-b-eu.temu.com',
      path: `/openapi/router?${qs}`,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) }
    };
    const req = https.request(opts, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({ raw: d }); } });
    });
    req.on('error', reject);
    req.write(payload);
    req.end();
  });
}

const recommendations = [];
let okCount = 0;
let errCount = 0;

for (const p of products) {
  const asin = String(p.asin || '').trim();
  const title = String(p.title || '').trim();
  const description = String(p.description || p.title || '').trim();
  const imageUrl = String(p.imageUrl || '').trim();

  if (!asin || !title) {
    recommendations.push({ asin, success: false, error: 'missing_asin_or_title' });
    errCount++;
    continue;
  }

  try {
    const resp = await temuPost('bg.local.goods.category.recommend', {
      goodsName: title,
      description,
      imageUrl
    });

    if (!resp.success) {
      recommendations.push({
        asin,
        success: false,
        error: resp.errorMsg || resp.error_msg || 'temu_api_error',
        raw: resp.errorCode || resp.error_code || null
      });
      errCount++;
    } else {
      const r = resp.result || {};
      const catId = r.catId || r.cat_id || (Array.isArray(r.catIdList) ? r.catIdList[0] : null);
      if (!catId) {
        recommendations.push({ asin, success: false, error: 'no_category_returned' });
        errCount++;
      } else {
        const catIdStr = String(catId);
        const catName = catNameById[catIdStr] || ('Categorie ' + catIdStr);
        recommendations.push({
          asin,
          success: true,
          categoryId: catIdStr,
          categoryName: catName,
          candidates: (r.catIdList || []).map(String)
        });
        okCount++;
      }
    }
  } catch(e) {
    recommendations.push({ asin, success: false, error: String(e.message || e) });
    errCount++;
  }

  // Rate limit: ~5 RPS
  await new Promise(r => setTimeout(r, 200));
}

return [{ json: {
  success: true,
  total: products.length,
  recommended: okCount,
  failed: errCount,
  recommendations
} }];
